<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  body{margin:0;font-family:sans-serif;background:#121212;color:#eee;text-align:center;}
  #score{font-size:2rem;margin:20px;}
  #board{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;width:400px;height:400px;margin:auto;background:#333;border-radius:8px;padding:10px;}
  .tile{background:#777;color:#fff;font-size:2rem;display:flex;align-items:center;justify-content:center;border-radius:4px;}
  #reset{margin-top:20px;padding:10px 20px;font-size:1rem;background:#555;color:#eee;border:none;border-radius:4px;cursor:pointer;}
</style>
</head>
<body>
<div id="score">Score: 0</div>
<div id="board"></div>
<button id="reset">New Game</button>

<script>
(() => {
  const size = 4;
  let board = Array.from({length:size},()=>Array(size).fill(0));
  let scoreVal=0;

  function render() {
    const container=document.getElementById('board');
    container.innerHTML='';
    for(let r=0;r<size;r++){
      for(let c=0;c<size;c++){
        const val=board[r][c];
        if(val){
          const div=document.createElement('div');
          div.className='tile';
          div.textContent=val;
          container.appendChild(div);
        }else{
          container.appendChild(document.createElement('div'));
        }
      }
    }
    document.getElementById('score').textContent=`Score: ${scoreVal}`;
  }

  function randomEmpty() {
    const empties=[];
    for(let r=0;r<size;r++)for(let c=0;c<size;c++)
      if(board[r][c]===0)empties.push([r,c]);
    if(!empties.length)return null;
    return empties[Math.floor(Math.random()*empties.length)];
  }

  function spawn() {
    const pos=randomEmpty();
    if(pos){
      board[pos[0]][pos[1]] = Math.random()<0.9?2:4;
    }
  }

  function slideLine(line) {
    const newLine=line.filter(v=>v!==0);
    let changed=false;
    for(let i=0;i<newLine.length-1;i++){
      if(newLine[i]===newLine[i+1]){
        newLine[i]*=2;
        scoreVal+=newLine[i];
        newLine.splice(i+1,1);
        changed=true;
      }
    }
    while(newLine.length<size)newLine.push(0);
    return {line:newLine,changed};
  }

  function move(dir){
    let moved=false;
    const temp=Array.from({length:size},()=>Array(size).fill(0));
    for(let r=0;r<size;r++){
      for(let c=0;c<size;c++){
        let val=board[r][c];
        if(!val)continue;
        let nr=r,nc=c;
        if(dir==='left') nc-=1;
        else if(dir==='right') nc+=1;
        else if(dir==='up') nr-=1;
        else if(dir==='down') nr+=1;
        while(nr>=0&&nr<size&&nc>=0&&nc<size){
          if(temp[nr][nc]===0){temp[nr][nc]=val;break;}
          if(temp[nr][nc]===val && !temp[`merged${nr}${nc}`]){
            temp[nr][nc]*=2;
            scoreVal+=temp[nr][nc];
            temp[`merged${nr}${nc}`]=true;
            break;
          }
          nr+= (dir==='left'||dir==='right')?0:(dir==='up'?-1:1);
          nc+= (dir==='up'||dir==='down')?0:(dir==='left'?-1:1);
        }
      }
    }
    // check difference
    for(let r=0;r<size;r++)for(let c=0;c<size;c++){
      if(board[r][c]!==temp[r][c]){moved=true;}
    }
    board=temp;
    render();
    if(moved)spawn();
    return moved;
  }

  function reset(){
    board = Array.from({length:size},()=>Array(size).fill(0));
    scoreVal=0;
    spawn();spawn();
    render();
  }

  document.getElementById('reset').addEventListener('click',reset);
  window.addEventListener('keydown',(e)=>{
    const map={ArrowLeft:'left',ArrowRight:'right',ArrowUp:'up',ArrowDown:'down'};
    if(map[e.key]){ e.preventDefault(); move(map[e.key]); }
  });

  // API
  window.game={
    size,
    reset:()=>reset(),
    move:(dir)=>move(dir),
    board:()=>board.map(row=>row.slice()),
    setBoard:(arr)=>{
      board=arr.map(r=>r.slice());
      render();
    },
    score:()=>scoreVal
  };

  reset();
})();
</script>
</body>
</html>
